function statusDotClass(status) {
    switch(status?.toLowerCase()){
        case "parked":
        case "completed":
        case "delivered":
            return "bg-emerald-500";
        case "started":
        case "ontheway":
        case "in_progress":
            return "bg-orange-500";
        case "accepted":
            return "bg-cyan-500";
        case "pending":
            return "bg-blue-500";
        case "cancelled":
            return "bg-red-500";
        default:
            return "bg-slate-500 dark:bg-slate-400";
    }
}
function statusBadgeClass(status) {
    switch(status?.toLowerCase()){
        case "parked":
        case "completed":
        case "delivered":
            return "bg-emerald-500/90 text-white dark:bg-emerald-600";
        case "started":
        case "ontheway":
        case "in_progress":
            return "bg-orange-500/90 text-white dark:bg-orange-600";
        case "accepted":
            return "bg-cyan-500/90 text-white dark:bg-cyan-600";
        case "pending":
            return "bg-blue-500/90 text-white dark:bg-blue-600";
        case "cancelled":
            return "bg-red-500/90 text-white dark:bg-red-600";
        default:
            return "bg-muted text-muted-foreground";
    }
}
